import { NextResponse } from "next/server";
import { 
  importVehicleFitment, 
  importAllVehicleVariants,
  listAvailableModifications,
} from "@/lib/fitmentImport";

export const runtime = "nodejs";
export const maxDuration = 60;

/**
 * GET /api/fitment/import?year=2024&make=Ford&model=F-150
 * List available modifications for a vehicle (preview before import)
 */
export async function GET(req: Request) {
  const url = new URL(req.url);
  const year = url.searchParams.get("year");
  const make = url.searchParams.get("make");
  const model = url.searchParams.get("model");
  const usMarketOnly = url.searchParams.get("usMarketOnly") !== "false";

  if (!year || !make || !model) {
    return NextResponse.json(
      { error: "Missing required params: year, make, model" },
      { status: 400 }
    );
  }

  const result = await listAvailableModifications(
    Number(year),
    make,
    model,
    { usMarketOnly }
  );

  return NextResponse.json(result, { status: result.success ? 200 : 404 });
}

/**
 * POST /api/fitment/import
 * Import fitment data from Wheel-Size API
 * 
 * Body: { 
 *   year: number, 
 *   make: string, 
 *   model: string, 
 *   modificationSlug?: string,  // Specific engine variant slug
 *   allVariants?: boolean,      // Import all engine variants
 *   usMarketOnly?: boolean,     // Filter to US market (default: true)
 *   debug?: boolean             // Include raw API response
 * }
 */
export async function POST(req: Request) {
  try {
    const body = await req.json();
    const { 
      year, 
      make, 
      model, 
      desiredTrim,
      modificationSlug,
      allVariants = false, 
      usMarketOnly = true,
      debug = false,
    } = body;

    if (!year || !make || !model) {
      return NextResponse.json(
        { error: "Missing required fields: year, make, model" },
        { status: 400 }
      );
    }

    if (allVariants) {
      // Import all engine variants
      const result = await importAllVehicleVariants(
        Number(year), 
        make, 
        model, 
        { usMarketOnly, debug }
      );
      return NextResponse.json(result, { status: result.success ? 200 : 400 });
    } else {
      // Import single variant (first USDM if no specific slug provided)
      const result = await importVehicleFitment(
        Number(year), 
        make, 
        model, 
        { desiredTrim, modificationSlug, usMarketOnly, debug }
      );
      return NextResponse.json(result, { status: result.success ? 200 : 400 });
    }
  } catch (err: any) {
    console.error("[api/fitment/import] Error:", err);
    return NextResponse.json(
      { error: err?.message || String(err) },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { getPool, buildFitmentProfile, ensureFitmentTables } from "@/lib/vehicleFitment";

export const runtime = "nodejs";

/**
 * GET /api/fitment/profile?year=2024&make=Ford&model=F-150&modification=s_abc123
 * Get the stored fitment profile for a vehicle
 * 
 * Params:
 * - modification: canonical fitment identity (preferred)
 * - trim: legacy param, falls back if modification not provided
 */
export async function GET(req: Request) {
  const url = new URL(req.url);
  const year = url.searchParams.get("year");
  const make = url.searchParams.get("make");
  const model = url.searchParams.get("model");

  // Prefer 'modification' param, fall back to 'trim' for backward compat
  const modification = url.searchParams.get("modification");
  const trimParam = url.searchParams.get("trim");
  const trim = modification || trimParam || undefined;

  if (!year || !make || !model) {
    return NextResponse.json(
      { error: "Missing required params: year, make, model" },
      { status: 400 }
    );
  }

  try {
    const db = getPool();
    await ensureFitmentTables(db);

    const profile = await buildFitmentProfile(db, Number(year), make, model, trim);

    if (!profile) {
      return NextResponse.json(
        { 
          error: "No fitment profile found. Import data first via POST /api/fitment/import",
          vehicle: { year, make, model, trim },
        },
        { status: 404 }
      );
    }

    return NextResponse.json({
      vehicle: profile.vehicle,
      fitment: profile.fitment,
      wheelSpecs: profile.wheelSpecs,
      derived: {
        allowedDiameters: profile.allowedDiameters,
        allowedWidths: profile.allowedWidths,
        allowedOffsets: profile.allowedOffsets,
        boltPattern: profile.boltPattern,
        centerBore: profile.centerBore,
      },
    });
  } catch (err: any) {
    console.error("[api/fitment/profile] Error:", err);
    return NextResponse.json(
      { error: err?.message || String(err) },
      { status: 500 }
    );
  }
}

/**
 * Fitment Import - Fetch from Wheel-Size API and store in database
 * 
 * USAGE:
 *   await importVehicleFitment(2024, "Ford", "F-150");  // Import first US-market engine variant
 *   await importAllVehicleVariants(2024, "Ford", "F-150");  // Import all engine variants
 * 
 * NOTES:
 * - Wheel-Size API organizes by ENGINE TYPE, not trim level (XLT/Lariat/etc)
 * - Each "modification" is an engine variant (2.7 EcoBoost, 5.0 V8, etc)
 * - All engines of the same type share the same bolt pattern/center bore
 * - Wheel specs (diameters/widths/offsets) may vary by engine
 */
import pg from "pg";
import * as wheelSizeApi from "./wheelSizeApi";
import {
  getPool,
  ensureFitmentTables,
  upsertVehicle,
  getVehicleBySlug,
  getVehicleFitment,
  getVehicleWheelSpecs,
  upsertVehicleFitment,
  clearVehicleWheelSpecs,
  insertVehicleWheelSpec,
  type Vehicle,
} from "./vehicleFitment";

export type ImportResult = {
  success: boolean;
  vehicle?: Vehicle;
  fitmentImported: boolean;
  wheelSpecsCount: number;
  modificationSlug?: string;
  modificationName?: string;
  cached?: boolean;
  selectionReason?: string;
  error?: string;
  rawData?: any;
};

export type BulkImportResult = {
  success: boolean;
  totalVehicles: number;
  totalWheelSpecs: number;
  results: ImportResult[];
  error?: string;
};

/**
 * Import fitment data for a specific vehicle/modification from Wheel-Size API
 * 
 * @param year - Vehicle year
 * @param make - Make name (e.g., "Ford") - will be resolved to slug
 * @param model - Model name (e.g., "F-150") - will be resolved to slug
 * @param options - Import options
 */
export async function importVehicleFitment(
  year: number,
  make: string,
  model: string,
  options: { 
    desiredTrim?: string;       // User-selected trim (e.g., "XLT") for modification selection
    modificationSlug?: string;  // Specific modification slug to import
    usMarketOnly?: boolean;     // Only import USDM modifications (default: true)
    debug?: boolean;
  } = {}
): Promise<ImportResult> {
  const { desiredTrim, modificationSlug, usMarketOnly = true, debug = false } = options;
  const db = getPool();

  try {
    await ensureFitmentTables(db);

    // Step 1: Resolve make slug
    console.log(`[fitmentImport] Resolving make: "${make}"`);
    const foundMake = await wheelSizeApi.findMake(make);
    if (!foundMake) {
      return {
        success: false,
        fitmentImported: false,
        wheelSpecsCount: 0,
        error: `Make "${make}" not found in Wheel-Size API`,
      };
    }
    const makeSlug = foundMake.slug;
    console.log(`[fitmentImport] Make resolved: ${make} -> ${makeSlug}`);

    // Step 2: Resolve model slug
    console.log(`[fitmentImport] Resolving model: "${model}"`);
    const foundModel = await wheelSizeApi.findModel(makeSlug, model);
    if (!foundModel) {
      return {
        success: false,
        fitmentImported: false,
        wheelSpecsCount: 0,
        error: `Model "${model}" not found for make "${make}"`,
      };
    }
    const modelSlug = foundModel.slug;
    console.log(`[fitmentImport] Model resolved: ${model} -> ${modelSlug}`);

    // Step 3: Choose modification slug (engine variant) using Wheel-Size modifications
    let selectedModSlug = modificationSlug;
    let selectedModName: string | undefined;
    let selectionReason: string | undefined;

    if (!selectedModSlug) {
      console.log(`[fitmentImport] Fetching modifications for ${year} ${makeSlug} ${modelSlug}`);
      let mods = await wheelSizeApi.getModifications(makeSlug, modelSlug, year);

      if (mods.length === 0) {
        return {
          success: false,
          fitmentImported: false,
          wheelSpecsCount: 0,
          error: `No modifications found for ${year} ${make} ${model}`,
        };
      }

      // Filter to US market if requested
      if (usMarketOnly) {
        const usdmMods = mods.filter(m => m.regions?.includes("usdm"));
        if (usdmMods.length > 0) {
          mods = usdmMods;
          console.log(`[fitmentImport] Filtered to ${mods.length} USDM modifications`);
        } else {
          console.log(`[fitmentImport] No USDM mods found, using all ${mods.length} modifications`);
        }
      }

      // If user selected a trim (e.g., XLT), prefer a modification whose trim_levels contains it
      if (desiredTrim) {
        const needle = desiredTrim.toLowerCase().trim();
        const trimMatches = mods.filter(m => (m.trim_levels || []).some(t => t?.toLowerCase?.() === needle));
        if (trimMatches.length > 0) {
          mods = trimMatches;
          selectionReason = `matched desiredTrim=${desiredTrim} via modification.trim_levels`;
          console.log(`[fitmentImport] Trim-based selection: ${desiredTrim} matched ${mods.length} modifications`);
        } else {
          console.log(`[fitmentImport] desiredTrim=${desiredTrim} did not match any modification.trim_levels; falling back`);
        }
      }

      // Deterministic selection: prefer USDM (already filtered), then pick first by name+slug
      mods.sort((a, b) => (a.name + a.slug).localeCompare(b.name + b.slug));

      selectedModSlug = mods[0].slug;
      selectedModName = mods[0].name;
      selectionReason = selectionReason || (usMarketOnly ? "first US-market modification (sorted)" : "first modification (sorted)");
      console.log(`[fitmentImport] Selected modification: ${selectedModSlug} (${selectedModName}) reason=${selectionReason}`);

      if (debug) {
        console.log(`[fitmentImport] modification.trim_levels for selected:`, mods[0].trim_levels || []);
      }
    }

    // Step 4: Check local cache first (avoid repeat Wheel-Size calls)
    const cachedVehicle = await getVehicleBySlug(db, year, foundMake.name, foundModel.name, selectedModSlug);
    if (cachedVehicle) {
      const cachedFitment = await getVehicleFitment(db, cachedVehicle.id);
      const cachedSpecs = await getVehicleWheelSpecs(db, cachedVehicle.id);
      if (cachedFitment && cachedSpecs.length > 0) {
        console.log(`[fitmentImport] Cache hit: vehicleId=${cachedVehicle.id} slug=${selectedModSlug}`);
        return {
          success: true,
          vehicle: cachedVehicle,
          fitmentImported: true,
          wheelSpecsCount: cachedSpecs.length,
          modificationSlug: selectedModSlug,
          modificationName: selectedModName,
          cached: true,
          selectionReason,
        };
      }
      console.log(`[fitmentImport] Cache partial: vehicle exists but missing fitment/specs; re-importing`);
    }

    // Step 5: Fetch vehicle data from Wheel-Size
    console.log(`[fitmentImport] Fetching Wheel-Size vehicle data for modification: ${selectedModSlug}`);
    const wsData = await wheelSizeApi.getVehicleData(makeSlug, modelSlug, year, selectedModSlug);

    if (!wsData) {
      return {
        success: false,
        fitmentImported: false,
        wheelSpecsCount: 0,
        modificationSlug: selectedModSlug,
        error: `No vehicle data returned for modification ${selectedModSlug}`,
      };
    }

    if (debug) {
      console.log("[fitmentImport] Raw Wheel-Size data:", JSON.stringify(wsData, null, 2));
    }

    // Step 6: Upsert vehicle record (cache key is slug)
    const vehicle = await upsertVehicle(db, {
      year,
      make: foundMake.name, // canonical
      model: foundModel.name, // canonical
      trim: wsData.trim || wsData.name, // engine/modification name
      searchTrim: desiredTrim,
      slug: wsData.slug,
      marketRegions: wsData.regions || [],
      importedFrom: "wheel_size",
      importStatus: "success",
      importedAt: new Date(),
      lastImportAttemptAt: new Date(),
    });
    console.log(`[fitmentImport] Vehicle upserted: id=${vehicle.id}`);

    // Step 6: Store technical fitment data
    let fitmentImported = false;
    if (wsData.technical) {
      const tech = wsData.technical;

      // Parse centre_bore (can be string or number)
      const centerBore = typeof tech.centre_bore === "string" 
        ? parseFloat(tech.centre_bore) 
        : tech.centre_bore;

      // Parse torque value (can be "204 Nm" string)
      let torqueNm: number | undefined;
      if (tech.wheel_tightening_torque) {
        const torqueMatch = String(tech.wheel_tightening_torque).match(/^(\d+)/);
        torqueNm = torqueMatch ? parseInt(torqueMatch[1], 10) : undefined;
      }

      // Thread size is nested in wheel_fasteners
      const threadSize = tech.wheel_fasteners?.thread_size;
      const fastenerType = tech.wheel_fasteners?.type;

      await upsertVehicleFitment(db, vehicle.id, {
        boltPattern: tech.bolt_pattern,
        centerBore,
        studHoles: tech.stud_holes,
        pcd: tech.pcd,
        threadSize,
        fastenerType,
        torqueNm,
      });
      fitmentImported = true;
      console.log(`[fitmentImport] Fitment stored: ${tech.bolt_pattern}, CB ${centerBore}mm`);
    }

    // Step 7: Store wheel specs with axle information
    let wheelSpecsCount = 0;
    if (wsData.wheels && wsData.wheels.length > 0) {
      await clearVehicleWheelSpecs(db, vehicle.id);

      for (const setup of wsData.wheels) {
        const front = setup.front;
        const rear = setup.rear;

        // Check if front and rear are different (staggered)
        const hasRear = rear && !setup.showing_fp_only && 
                        rear.rim_diameter && rear.rim_width;

        const isDifferent = !!(hasRear && rear && front && (
          rear.rim_diameter !== front.rim_diameter ||
          rear.rim_width !== front.rim_width ||
          rear.rim_offset !== front.rim_offset ||
          rear.tire !== front.tire
        ));

        // Front wheel/tire
        if (front && front.rim_diameter) {
          await insertVehicleWheelSpec(db, vehicle.id, {
            rimDiameter: front.rim_diameter,
            rimWidth: front.rim_width,
            offset: front.rim_offset,
            tireSize: front.tire,
            // If different front/rear, mark as "front"; otherwise "both"
            axle: isDifferent ? "front" : "both",
            isStock: setup.is_stock,
          });
          wheelSpecsCount++;
        }

        // Rear wheel/tire (only if staggered - different from front)
        if (isDifferent && hasRear && rear && front) {
          await insertVehicleWheelSpec(db, vehicle.id, {
            rimDiameter: rear.rim_diameter!,
            rimWidth: rear.rim_width!,
            offset: rear.rim_offset ?? null,
            tireSize: rear.tire ?? null,
            axle: "rear",
            isStock: setup.is_stock,
          });
          wheelSpecsCount++;
          console.log(`[fitmentImport] Staggered setup detected: F=${front.rim_diameter}x${front.rim_width} R=${rear.rim_diameter}x${rear.rim_width}`);
        }
      }
      console.log(`[fitmentImport] Stored ${wheelSpecsCount} wheel specs`);
    }

    return {
      success: true,
      vehicle,
      fitmentImported,
      wheelSpecsCount,
      modificationSlug: selectedModSlug,
      modificationName: selectedModName || wsData.name,
      cached: false,
      selectionReason,
      rawData: debug ? wsData : undefined,
    };
  } catch (err: any) {
    console.error("[fitmentImport] Error:", err);
    return {
      success: false,
      fitmentImported: false,
      wheelSpecsCount: 0,
      error: err?.message || String(err),
    };
  }
}

/**
 * Import ALL engine variants for a year/make/model
 * Creates separate vehicle records for each engine variant
 */
export async function importAllVehicleVariants(
  year: number,
  make: string,
  model: string,
  options: { 
    usMarketOnly?: boolean;
    debug?: boolean;
  } = {}
): Promise<BulkImportResult> {
  const { usMarketOnly = true, debug = false } = options;
  const results: ImportResult[] = [];

  try {
    // Resolve slugs
    const foundMake = await wheelSizeApi.findMake(make);
    if (!foundMake) {
      return {
        success: false,
        totalVehicles: 0,
        totalWheelSpecs: 0,
        results: [],
        error: `Make "${make}" not found`,
      };
    }

    const foundModel = await wheelSizeApi.findModel(foundMake.slug, model);
    if (!foundModel) {
      return {
        success: false,
        totalVehicles: 0,
        totalWheelSpecs: 0,
        results: [],
        error: `Model "${model}" not found for make "${make}"`,
      };
    }

    // Get all modifications
    let mods = await wheelSizeApi.getModifications(foundMake.slug, foundModel.slug, year);

    if (usMarketOnly) {
      const usdmMods = mods.filter(m => m.regions?.includes("usdm"));
      if (usdmMods.length > 0) {
        mods = usdmMods;
      }
    }

    if (mods.length === 0) {
      return {
        success: false,
        totalVehicles: 0,
        totalWheelSpecs: 0,
        results: [],
        error: `No modifications found for ${year} ${make} ${model}`,
      };
    }

    console.log(`[fitmentImport] Importing ${mods.length} variants for ${year} ${make} ${model}`);

    // Import each modification
    for (const mod of mods) {
      console.log(`[fitmentImport] Importing variant: ${mod.name} (${mod.slug})`);
      const result = await importVehicleFitment(year, make, model, {
        modificationSlug: mod.slug,
        usMarketOnly: false,  // Already filtered
        debug,
      });
      results.push(result);
    }

    const totalVehicles = results.filter(r => r.success).length;
    const totalWheelSpecs = results.reduce((sum, r) => sum + r.wheelSpecsCount, 0);

    return {
      success: totalVehicles > 0,
      totalVehicles,
      totalWheelSpecs,
      results,
    };
  } catch (err: any) {
    console.error("[fitmentImport] Bulk import error:", err);
    return {
      success: false,
      totalVehicles: 0,
      totalWheelSpecs: 0,
      results,
      error: err?.message || String(err),
    };
  }
}

/**
 * List available modifications for a vehicle (for UI selection)
 */
export async function listAvailableModifications(
  year: number,
  make: string,
  model: string,
  options: { usMarketOnly?: boolean } = {}
): Promise<{
  success: boolean;
  makeSlug?: string;
  modelSlug?: string;
  modifications: Array<{
    slug: string;
    name: string;
    engine?: string;
    regions: string[];
  }>;
  error?: string;
}> {
  try {
    const foundMake = await wheelSizeApi.findMake(make);
    if (!foundMake) {
      return { success: false, modifications: [], error: `Make "${make}" not found` };
    }

    const foundModel = await wheelSizeApi.findModel(foundMake.slug, model);
    if (!foundModel) {
      return { success: false, modifications: [], error: `Model "${model}" not found` };
    }

    let mods = await wheelSizeApi.getModifications(foundMake.slug, foundModel.slug, year);

    if (options.usMarketOnly) {
      mods = mods.filter(m => m.regions?.includes("usdm"));
    }

    return {
      success: true,
      makeSlug: foundMake.slug,
      modelSlug: foundModel.slug,
      modifications: mods.map(m => ({
        slug: m.slug,
        name: m.name,
        engine: m.engine ? `${m.engine.capacity}L ${m.engine.type} ${m.engine.fuel}` : undefined,
        regions: m.regions || [],
      })),
    };
  } catch (err: any) {
    return {
      success: false,
      modifications: [],
      error: err?.message || String(err),
    };
  }
}

/**
 * Vehicle Fitment Engine
 * Uses Wheel-Size API data as source of truth for strict wheel validation
 */
import pg from "pg";
import { normalizeModelForApi } from "./fitment-db/keys";

const { Pool } = pg;

// ─────────────────────────────────────────────────────────────────────────────
// TYPES
// ─────────────────────────────────────────────────────────────────────────────

export type Vehicle = {
  id: number;
  year: number;
  make: string;
  model: string;
  trim: string | null;
  slug: string | null; // Wheel-Size modification slug
  createdAt: Date;
  updatedAt: Date;
};

export type VehicleFitment = {
  id: number;
  vehicleId: number;
  boltPattern: string;       // e.g., "6x135"
  centerBore: number;        // mm, e.g., 87.1
  studHoles: number;         // e.g., 6
  pcd: number;               // mm, e.g., 135
  threadSize: string | null; // e.g., "M14x1.5"
  fastenerType: string | null; // "lug_nut" | "lug_bolt"
  torqueNm: number | null;
  createdAt: Date;
  updatedAt: Date;
};

export type VehicleWheelSpec = {
  id: number;
  vehicleId: number;
  rimDiameter: number;       // inches, e.g., 17
  rimWidth: number;          // inches, e.g., 7.5
  offset: number | null;     // mm, e.g., 44 (can be null for some plus sizes)
  tireSize: string | null;   // e.g., "265/70R17"
  axle: "front" | "rear" | "both";  // which axle this spec is for
  isStock: boolean;
  createdAt: Date;
  updatedAt: Date;
};

export type StaggeredInfo = {
  isStaggered: boolean;
  reason: string;
  frontSpec?: {
    diameter: number;
    width: number;
    offset: number | null;
    tireSize: string | null;
  };
  rearSpec?: {
    diameter: number;
    width: number;
    offset: number | null;
    tireSize: string | null;
  };
};

export type FitmentProfile = {
  vehicle: Vehicle;
  fitment: VehicleFitment;
  wheelSpecs: VehicleWheelSpec[];
  // Derived allowed values
  allowedDiameters: number[];
  allowedWidths: number[];
  allowedOffsets: number[];
  boltPattern: string;
  centerBore: number;
  // Staggered fitment info
  staggered: StaggeredInfo;
};

export type FitmentClass = "surefit" | "specfit" | "excluded";

export type WheelValidation = {
  sku: string;
  boltPatternPass: boolean;
  centerBorePass: boolean;
  diameterPass: boolean;
  widthPass: boolean;
  offsetPass: boolean;
  fitmentClass: FitmentClass;
  exclusionReasons: string[];
};

export type WheelToValidate = {
  sku: string;
  boltPattern?: string;
  centerBore?: number;
  diameter?: number;
  width?: number;
  offset?: number;
};

// ─────────────────────────────────────────────────────────────────────────────
// DATABASE CONNECTION
// ─────────────────────────────────────────────────────────────────────────────

let pool: pg.Pool | null = null;

export function getPool(): pg.Pool {
  if (pool) return pool;
  pool = new Pool({
    connectionString: process.env.DATABASE_URL,
    max: 5,
  });
  return pool;
}

// ─────────────────────────────────────────────────────────────────────────────
// SCHEMA INITIALIZATION
// ─────────────────────────────────────────────────────────────────────────────

export async function ensureFitmentTables(db: pg.Pool): Promise<void> {
  await db.query(`
    CREATE TABLE IF NOT EXISTS vehicles (
      id SERIAL PRIMARY KEY,
      year INTEGER NOT NULL,
      make VARCHAR(100) NOT NULL,
      model VARCHAR(100) NOT NULL,
      trim VARCHAR(100),
      search_trim VARCHAR(100),
      slug VARCHAR(255), -- Wheel-Size modification slug
      market_regions VARCHAR(255),
      imported_from VARCHAR(50),
      imported_at TIMESTAMP WITH TIME ZONE,
      import_status VARCHAR(20),
      last_import_error TEXT,
      last_import_attempt_at TIMESTAMP WITH TIME ZONE,
      created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
      updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
      UNIQUE(year, make, model, trim)
    );

    CREATE TABLE IF NOT EXISTS vehicle_fitment (
      id SERIAL PRIMARY KEY,
      vehicle_id INTEGER NOT NULL REFERENCES vehicles(id) ON DELETE CASCADE,
      bolt_pattern VARCHAR(20) NOT NULL,
      center_bore DECIMAL(6,2) NOT NULL,
      stud_holes INTEGER NOT NULL,
      pcd DECIMAL(6,2) NOT NULL,
      thread_size VARCHAR(20),
      fastener_type VARCHAR(20),
      torque_nm INTEGER,
      imported_at TIMESTAMP WITH TIME ZONE,
      created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
      updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
      UNIQUE(vehicle_id)
    );

    CREATE TABLE IF NOT EXISTS vehicle_wheel_specs (
      id SERIAL PRIMARY KEY,
      vehicle_id INTEGER NOT NULL REFERENCES vehicles(id) ON DELETE CASCADE,
      rim_diameter DECIMAL(4,1) NOT NULL,
      rim_width DECIMAL(4,2) NOT NULL,
      "offset" DECIMAL(5,2),
      tire_size VARCHAR(30),
      axle VARCHAR(10) DEFAULT 'both',  -- front, rear, or both
      is_stock BOOLEAN DEFAULT true,
      imported_at TIMESTAMP WITH TIME ZONE,
      created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
      updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
    );

    CREATE INDEX IF NOT EXISTS idx_vehicles_year_make_model ON vehicles(year, make, model);
    CREATE INDEX IF NOT EXISTS idx_vehicles_year_make_model_slug ON vehicles(year, make, model, slug);
    CREATE INDEX IF NOT EXISTS idx_vehicle_wheel_specs_vehicle_id ON vehicle_wheel_specs(vehicle_id);

    -- Allow NULL offset for existing tables
    ALTER TABLE vehicle_wheel_specs ALTER COLUMN "offset" DROP NOT NULL;

    -- Change offset from INTEGER to DECIMAL for API values like 44.45
    ALTER TABLE vehicle_wheel_specs ALTER COLUMN "offset" TYPE DECIMAL(5,2) USING "offset"::DECIMAL(5,2);

    -- Add missing columns for existing deployments (safe no-ops if present)
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS search_trim VARCHAR(100);
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS market_regions VARCHAR(255);
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS imported_from VARCHAR(50);
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS imported_at TIMESTAMP WITH TIME ZONE;
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS import_status VARCHAR(20);
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS last_import_error TEXT;
    ALTER TABLE vehicles ADD COLUMN IF NOT EXISTS last_import_attempt_at TIMESTAMP WITH TIME ZONE;

    ALTER TABLE vehicle_fitment ADD COLUMN IF NOT EXISTS imported_at TIMESTAMP WITH TIME ZONE;
    ALTER TABLE vehicle_wheel_specs ADD COLUMN IF NOT EXISTS imported_at TIMESTAMP WITH TIME ZONE;
    ALTER TABLE vehicle_wheel_specs ADD COLUMN IF NOT EXISTS axle VARCHAR(10) DEFAULT 'both';

    -- Ensure uniqueness for caching: year/make/model/modification_slug (vehicles.slug)
    DO $$
    BEGIN
      IF NOT EXISTS (
        SELECT 1 FROM pg_constraint WHERE conname = 'vehicles_year_make_model_slug_unique'
      ) THEN
        ALTER TABLE vehicles ADD CONSTRAINT vehicles_year_make_model_slug_unique UNIQUE (year, make, model, slug);
      END IF;
    END$$;
  `);
}

