export async function upsertVehicle(
  db: pg.Pool,
  data: {
    year: number;
    make: string;
    model: string;
    trim?: string;
    searchTrim?: string;
    slug?: string; // modification slug
    marketRegions?: string[];
    importedFrom?: string;
    importedAt?: Date;
    importStatus?: "pending" | "success" | "failed";
    lastImportError?: string;
    lastImportAttemptAt?: Date;
  }
): Promise<Vehicle> {
  // Prefer caching by (year, make, model, slug) when slug is present.
  // Fallback to legacy unique (year, make, model, trim) if slug is null.
  const marketRegions = data.marketRegions?.length ? data.marketRegions.join(",") : null;

  if (data.slug) {
    const result = await db.query<Vehicle>(
      `INSERT INTO vehicles (year, make, model, trim, search_trim, slug, market_regions, imported_from, imported_at, import_status, last_import_error, last_import_attempt_at, updated_at)
       VALUES ($1, $2, $3, $4, $5, $6, $7, $8, COALESCE($9, NOW()), $10, $11, COALESCE($12, NOW()), NOW())
       ON CONFLICT (year, make, model, slug)
       DO UPDATE SET 
         trim = COALESCE($4, vehicles.trim),
         search_trim = COALESCE($5, vehicles.search_trim),
         market_regions = COALESCE($7, vehicles.market_regions),
         imported_from = COALESCE($8, vehicles.imported_from),
         imported_at = COALESCE(vehicles.imported_at, $9, NOW()),
         import_status = COALESCE($10, vehicles.import_status),
         last_import_error = $11,
         last_import_attempt_at = COALESCE($12, NOW()),
         updated_at = NOW()
       RETURNING id, year, make, model, trim, slug, created_at, updated_at`,
      [
        data.year,
        data.make,
        data.model,
        data.trim || null,
        // search_trim: what the user selected (e.g., XLT)
        data.searchTrim || null,
        data.slug,
        marketRegions,
        data.importedFrom || null,
        data.importedAt || null,
        data.importStatus || null,
        data.lastImportError || null,
        data.lastImportAttemptAt || null,
      ]
    );
    return result.rows[0];
  }

  const result = await db.query<Vehicle>(
    `INSERT INTO vehicles (year, make, model, trim, search_trim, slug, market_regions, imported_from, imported_at, import_status, last_import_error, last_import_attempt_at, updated_at)
     VALUES ($1, $2, $3, $4, $5, $6, $7, $8, COALESCE($9, NOW()), $10, $11, COALESCE($12, NOW()), NOW())
     ON CONFLICT (year, make, model, trim) 
     DO UPDATE SET 
       search_trim = COALESCE($5, vehicles.search_trim),
       slug = COALESCE($6, vehicles.slug),
       market_regions = COALESCE($7, vehicles.market_regions),
       imported_from = COALESCE($8, vehicles.imported_from),
       imported_at = COALESCE(vehicles.imported_at, $9, NOW()),
       import_status = COALESCE($10, vehicles.import_status),
       last_import_error = $11,
       last_import_attempt_at = COALESCE($12, NOW()),
       updated_at = NOW()
     RETURNING id, year, make, model, trim, slug, created_at, updated_at`,
    [
      data.year,
      data.make,
      data.model,
      data.trim || null,
      data.searchTrim || null,
      data.slug || null,
      marketRegions,
      data.importedFrom || null,
      data.importedAt || null,
      data.importStatus || null,
      data.lastImportError || null,
      data.lastImportAttemptAt || null,
    ]
  );
  return result.rows[0];
}

export async function getVehicle(
  db: pg.Pool,
  year: number,
  make: string,
  model: string,
  trim?: string
): Promise<Vehicle | null> {
  // Normalize lookup value for comparison
  const lookupTrim = trim?.trim().toLowerCase() ?? null;
  // Also normalize model for cases like "RX 350" → "RX"
  const normalizedModel = normalizeModelForApi(model);

  // First, try exact match on trim, search_trim, or slug
  // Check both original model and normalized model (for aliases like RX 350 → RX)
  const result = await db.query<Vehicle>(
    `SELECT id, year, make, model, trim, slug, created_at, updated_at
     FROM vehicles
     WHERE year = $1 AND make = $2 AND (model = $3 OR LOWER(model) = $5)
       AND (
         $4::text IS NULL OR 
         LOWER(TRIM(trim)) = $4 OR 
         LOWER(TRIM(search_trim)) = $4 OR
         LOWER(TRIM(slug)) = $4
       )
     ORDER BY imported_at DESC NULLS LAST, updated_at DESC
     LIMIT 1`,
    [year, make, model, lookupTrim, normalizedModel]
  );

  if (result.rows[0]) {
    return result.rows[0];
  }

  // Fallback: if no exact match but trim looks like a modification ID (alphanumeric hash),
  // try to find any vehicle for this Y/M/M and use the most recently imported one
  if (trim && /^[a-f0-9]{8,}$/i.test(trim)) {
    console.log(`[getVehicle] Trim "${trim}" looks like a modification slug, trying slug match`);
    const slugResult = await db.query<Vehicle>(
      `SELECT id, year, make, model, trim, slug, created_at, updated_at
       FROM vehicles
       WHERE year = $1 AND make = $2 AND (model = $3 OR LOWER(model) = $5) AND slug = $4
       ORDER BY imported_at DESC NULLS LAST, updated_at DESC
       LIMIT 1`,
      [year, make, model, trim, normalizedModel]
    );
    if (slugResult.rows[0]) {
      return slugResult.rows[0];
    }
  }

  // Final fallback: if trim specified but no match, return any vehicle for this Y/M/M
  // This ensures we have SOME fitment data rather than failing completely
  if (trim) {
    console.log(`[getVehicle] No exact match for trim="${trim}", falling back to any vehicle for ${year} ${make} ${model}`);
    const fallbackResult = await db.query<Vehicle>(
      `SELECT id, year, make, model, trim, slug, created_at, updated_at
       FROM vehicles
       WHERE year = $1 AND make = $2 AND (model = $3 OR LOWER(model) = $4)
       ORDER BY imported_at DESC NULLS LAST, updated_at DESC
       LIMIT 1`,
      [year, make, model, normalizedModel]
    );
    return fallbackResult.rows[0] || null;
  }

  return null;
}

export async function getVehicleBySlug(
  db: pg.Pool,
