arguments.command:
$ProgressPreference = 'SilentlyContinue'

# Check each vehicle against the API
$vehicles = @(
    @{year=2020; make="BMW"; model="M340i"},
    @{year=2022; make="Mercedes-Benz"; model="GLE 350"},
    @{year=2016; make="Mercedes-Benz"; model="CLA 250"},
    @{year=2022; make="Tesla"; model="Model 3 Long Range"}
)

foreach ($v in $vehicles) {
    Write-Host "`n=== $($v.year) $($v.make) $($v.model) ===" -ForegroundColor Cyan
    $url = "https://shop.warehousetiredirect.com/api/fitment/import?year=$($v.year)&make=$([uri]::EscapeDataString($v.make))&model=$([uri]::EscapeDataString($v.model))"
    try {
        $result = Invoke-RestMethod -Uri $url
        Write-Host "API Response:"
        Write-Host "  makeSlug: $($result.makeSlug)"
        Write-Host "  modelSlug: $($result.modelSlug)"
        Write-Host "  modifications: $($result.modifications.Count)"
        if ($result.modifications) {
            $result.modifications | ForEach-Object { Write-Host "    - $($_.name) ($($_.slug))" }
        }
    } catch {
        Write-Host "Error: $($_.Exception.Message)" -ForegroundColor Red
    }
}

$ProgressPreference = 'SilentlyContinue'

# Check the trims endpoint for M340i and Tesla (which have API data)
Write-Host "=== BMW M340i - Trims Check ===" -ForegroundColor Cyan
$url = "https://shop.warehousetiredirect.com/api/fitment/trims?year=2020&make=BMW&model=M340i"
try { Invoke-RestMethod -Uri $url | ConvertTo-Json -Depth 3 } catch { Write-Host "Error: $($_.Exception.Message)" }

Write-Host "`n=== Tesla Model 3 Long Range - Trims Check ===" -ForegroundColor Cyan
$url = "https://shop.warehousetiredirect.com/api/fitment/trims?year=2022&make=Tesla&model=Model%203%20Long%20Range"
try { Invoke-RestMethod -Uri $url | ConvertTo-Json -Depth 3 } catch { Write-Host "Error: $($_.Exception.Message)" }

# Check if GLE 350 exists with different year
Write-Host "`n=== Mercedes GLE 350 - Year Check ===" -ForegroundColor Cyan
foreach ($y in @(2020, 2021, 2023)) {
    $url = "https://shop.warehousetiredirect.com/api/fitment/import?year=$y&make=Mercedes-Benz&model=GLE%20350"
    try { 
        $r = Invoke-RestMethod -Uri $url
        Write-Host "Year $y : Found! modelSlug=$($r.modelSlug), $($r.modifications.Count) mods"
    } catch { Write-Host "Year $y : 404" }
}

# Check CLA 250 with different years
Write-Host "`n=== Mercedes CLA 250 - Year Check ===" -ForegroundColor Cyan
foreach ($y in @(2017, 2018, 2019, 2020)) {
    $url = "https://shop.warehousetiredirect.com/api/fitment/import?year=$y&make=Mercedes-Benz&model=CLA%20250"
    try { 
        $r = Invoke-RestMethod -Uri $url
        Write-Host "Year $y : Found! modelSlug=$($r.modelSlug), $($r.modifications.Count) mods"
    } catch { Write-Host "Year $y : 404" }
}

$ProgressPreference = 'SilentlyContinue'

# Check what models exist for Mercedes GLE and CLA
Write-Host "=== Mercedes GLE models (2022) ===" -ForegroundColor Cyan
$url = "https://shop.warehousetiredirect.com/api/fitment/models?year=2022&make=Mercedes-Benz"
try { 
    $r = Invoke-RestMethod -Uri $url
    $r.models | Where-Object { $_.name -like "*GLE*" -or $_.name -like "*GLC*" } | ForEach-Object { Write-Host "  $($_.name) ($($_.slug))" }
} catch { Write-Host "Error" }

Write-Host "`n=== Mercedes CLA models (2016) ===" -ForegroundColor Cyan
$url = "https://shop.warehousetiredirect.com/api/fitment/models?year=2016&make=Mercedes-Benz"
try { 
    $r = Invoke-RestMethod -Uri $url
    $r.models | Where-Object { $_.name -like "*CLA*" } | ForEach-Object { Write-Host "  $($_.name) ($($_.slug))" }
} catch { Write-Host "Error" }

# Check why M340i trims fails - what does the trims endpoint return for "3-series"?
Write-Host "`n=== BMW 3-series trims (2020) - direct ===" -ForegroundColor Cyan
$url = "https://shop.warehousetiredirect.com/api/fitment/trims?year=2020&make=BMW&model=3-series"
try { 
    $r = Invoke-RestMethod -Uri $url
    Write-Host "Found $($r.trims.Count) trims"
    $r.trims | Select-Object -First 5 | ForEach-Object { Write-Host "  $($_.name) ($($_.slug))" }
} catch { Write-Host "Error: $($_.Exception.Message)" }

# Check Tesla model-3 trims
Write-Host "`n=== Tesla Model 3 trims (2022) - direct ===" -ForegroundColor Cyan
$url = "https://shop.warehousetiredirect.com/api/fitment/trims?year=2022&make=Tesla&model=Model%203"
try { 
    $r = Invoke-RestMethod -Uri $url
    Write-Host "Found $($r.trims.Count) trims"
    $r.trims | ForEach-Object { Write-Host "  $($_.name) ($($_.slug))" }
} catch { Write-Host "Error: $($_.Exception.Message)" }

$ProgressPreference = 'SilentlyContinue'

# Check Mercedes models with alternate make name
Write-Host "=== Mercedes (as 'Mercedes') models 2022 ===" -ForegroundColor Cyan
$url = "https://shop.warehousetiredirect.com/api/fitment/models?year=2022&make=Mercedes"
try { 
    $r = Invoke-RestMethod -Uri $url
    Write-Host "Found $($r.models.Count) models"
    $r.models | Where-Object { $_.name -like "*GLE*" -or $_.name -like "*CLA*" } | ForEach-Object { Write-Host "  $($_.name) ($($_.slug))" }
} catch { Write-Host "Error: $($_.Exception.Message)" }

# Check what the trims endpoint code does - look at profileService for clues
Write-Host "`n=== BMW 330i trims (2020) - should work ===" -ForegroundColor Cyan
$url = "https://shop.warehousetiredirect.com/api/fitment/trims?year=2020&make=BMW&model=330i"
try { 
    $r = Invoke-RestMethod -Uri $url
    Write-Host "Found $($r.trims.Count) trims"
    $r.trims | Select-Object -First 3 | ForEach-Object { Write-Host "  $($_.name) ($($_.slug))" }
} catch { Write-Host "Error: $($_.Exception.Message)" }

$ProgressPreference = 'SilentlyContinue'

# Verbose check of trims endpoint
Write-Host "=== Checking trims endpoint verbose ===" -ForegroundColor Cyan
$url = "https://shop.warehousetiredirect.com/api/fitment/trims?year=2020&make=BMW&model=330i"
try { 
    Invoke-WebRequest -Uri $url -UseBasicParsing
} catch { 
    Write-Host "Status: $($_.Exception.Response.StatusCode)"
    $reader = [System.IO.StreamReader]::new($_.Exception.Response.GetResponseStream())
    Write-Host "Body: $($reader.ReadToEnd())"
}

# Check if M340i exists in API at all
Write-Host "`n=== Direct Wheel-Size API check for M340i ===" -ForegroundColor Cyan
$importUrl = "https://shop.warehousetiredirect.com/api/fitment/import?year=2020&make=BMW&model=330i"
try { 
    $r = Invoke-RestMethod -Uri $importUrl
    Write-Host "Import found: makeSlug=$($r.makeSlug), modelSlug=$($r.modelSlug)"
    Write-Host "Modifications:"
    $r.modifications | ForEach-Object { Write-Host "  - $($_.name) ($($_.slug))" }
} catch { Write-Host "Error" }

